import{_ as i,o as t,c as r,a2 as n}from"./chunks/framework.Cuq8tsM6.js";const g=JSON.parse('{"title":"2. Production (Distributeur)","description":"","frontmatter":{"title":"2. Production (Distributeur)"},"headers":[],"relativePath":"docs/fr/advertisers/dedicated-email/2-creation-distributeur.md","filePath":"docs/fr/advertisers/dedicated-email/2-creation-distributeur.md"}'),o={name:"docs/fr/advertisers/dedicated-email/2-creation-distributeur.md"};function a(s,e,d,l,u,p){return t(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="etape-2-production-co-branding" tabindex="-1">Étape 2 : Production &amp; Co-branding <a class="header-anchor" href="#etape-2-production-co-branding" aria-label="Permalink to &quot;Étape 2 : Production &amp; Co-branding&quot;">​</a></h1><p>Une fois votre brief envoyé, c&#39;est le Distributeur qui prend le relais pour concevoir l&#39;email. Voici pourquoi et comment cela fonctionne.</p><hr><h2>Pourquoi ce n&#39;est pas vous qui créez l&#39;email ?</h2><div style="background:var(--gi-tint-blue-bg);border:2px solid var(--gi-accent);border-radius:8px;padding:24px;margin-bottom:40px;"><h3>🤝 La force de l&#39;Endorsement (Recommandation)</h3><p>L&#39;objectif n&#39;est pas d&#39;envoyer une publicité brute, mais une <strong>recommandation de la part du partenaire</strong>.</p><p>Les abonnés du Distributeur lui font confiance. Pour maximiser le taux d&#39;ouverture et de clic, l&#39;email doit respecter les codes graphiques et le ton habituel de la newsletter qu&#39;ils reçoivent chaque semaine.</p></div><h2>À quoi va ressembler votre campagne ?</h2><div style="display:flex;gap:20px;flex-wrap:wrap;margin-bottom:40px;"><div style="flex:1;min-width:300px;border:1px solid var(--gi-tint-green-text);background:var(--gi-tint-green-bg);border-radius:8px;padding:20px;"><h3>✅ Le Résultat Attendu (Natif)</h3><ul><li><strong>Header Partenaire :</strong> Le logo et le menu du Distributeur restent en haut pour rassurer l&#39;abonné.</li><li><strong>Édito d&#39;intro :</strong> Le Distributeur rédige une phrase d&#39;accroche (ex: <em>&quot;Aujourd&#39;hui, nous vous présentons notre coup de cœur...&quot;</em>).</li><li><strong>Vos Assets :</strong> Vos visuels et votre offre sont intégrés au centre, mais avec les boutons et polices du partenaire.</li></ul></div><div style="flex:1;min-width:300px;border:1px solid var(--gi-tint-red-text);background:var(--gi-tint-red-bg);border-radius:8px;padding:20px;"><h3>❌ Ce qui est évité (Full Brand)</h3><p>Nous évitons d&#39;envoyer un email qui ressemble à 100% à votre site web sans mention du partenaire.</p><p><em>Pourquoi ? Car cela crée une dissonance cognitive chez l&#39;abonné (&quot;Pourquoi je reçois ça ?&quot;), augmente le taux de désabonnement et fait chuter la performance.</em></p></div></div><h2>Le flux de production</h2><div style="display:flex;flex-direction:column;gap:15px;margin-bottom:40px;"><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:20px;background:var(--vp-c-bg-elv);display:flex;align-items:center;gap:20px;"><div style="font-size:24px;min-width:40px;text-align:center;">🎨</div><div><strong class="d-block">1. Conception</strong><span>Le Distributeur (ou le Studio getinside) assemble l&#39;email en utilisant les éléments de votre brief.</span></div></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:20px;background:var(--vp-c-bg-elv);display:flex;align-items:center;gap:20px;"><div style="font-size:24px;min-width:40px;text-align:center;">⚙️</div><div><strong class="d-block">2. Intégration Technique</strong><span>Les liens de tracking sont générés et insérés pour suivre vos ventes. Le code est optimisé pour la délivrabilité.</span></div></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:20px;background:var(--vp-c-bg-elv);display:flex;align-items:center;gap:20px;"><div style="font-size:24px;min-width:40px;text-align:center;">👀</div><div><strong class="d-block">3. Review Interne</strong><span>L&#39;équipe getinside vérifie la qualité technique avant de vous soumettre le résultat.</span></div></div></div><div style="background:var(--gi-tint-blue-bg);border:1px solid var(--gi-accent);border-radius:8px;padding:24px;margin-bottom:40px;"><h3>🔄 Flexibilité : Vos liens sont dynamiques !</h3><p>Une erreur dans le brief ? Vous changez de Landing Page à la dernière minute ?</p><p>Pas de panique. Comme pour nos QR codes, les liens de tracking emails sont <strong>dynamiques</strong>.</p><ul><li>Vous pouvez modifier l&#39;URL de destination finale à tout moment dans l&#39;onglet <strong>&quot;Configuration et Suivi&quot;</strong> de votre campagne.</li><li>La mise à jour est <strong>instantanée</strong>, même si le Distributeur a déjà intégré le lien ou si la campagne est prête à partir.</li></ul></div><div class="gi-info-box"><h4>Et ensuite ?</h4><p>Dès que la création est prête, vous recevez une notification pour passer à l&#39;étape de <strong>Validation (BAT)</strong>.</p></div>',11)])])}const v=i(o,[["render",a]]);export{g as __pageData,v as default};
